sys_script_include.script:
var RequestValidationUtil = Class.create();
RequestValidationUtil.prototype = {

    initialize: function() {
    },

    canCompleteRequest: function(current) {

        if (current.approval_state != 'Approved') {
            return {
                valid: false,
                message: 'The request must be approved before it can be completed.'
            };
        }

        if (current.assignment_group.nil()) {
            return {
                valid: false,
                message: 'Assignment Group is required before completing the request.'
            };
        }

        if (current.assigned_to.nil()) {
            return {
                valid: false,
                message: 'Assigned To is required before completing the request.'
            };
        }

        return {
            valid: true,
            message: ''
        };
    },

    type: 'RequestValidationUtil'
};
